"""Minimal RV32I+M interpreter for eval purposes.
Supports: integer ops, M-extension (mul/div/rem), loads/stores, branches, jal/jalr, ret,
common pseudo-instructions (li, mv, neg, not, j, jr, beqz, bnez, bgez, bltz).
Calling convention: a0-a7 args, a0/a1 return, ra=x1, sp=x2.
Memory is a flat byte array; sp starts near the top."""

import re

REGS = {'zero': 0, 'ra': 1, 'sp': 2, 'gp': 3, 'tp': 4,
        't0': 5, 't1': 6, 't2': 7, 's0': 8, 'fp': 8, 's1': 9,
        'a0': 10, 'a1': 11, 'a2': 12, 'a3': 13, 'a4': 14, 'a5': 15, 'a6': 16, 'a7': 17,
        's2': 18, 's3': 19, 's4': 20, 's5': 21, 's6': 22, 's7': 23,
        's8': 24, 's9': 25, 's10': 26, 's11': 27,
        't3': 28, 't4': 29, 't5': 30, 't6': 31}
for _i in range(32):
    REGS[f'x{_i}'] = _i


def s32(v):
    v &= 0xFFFFFFFF
    return v - 0x100000000 if v >= 0x80000000 else v


def u32(v):
    return v & 0xFFFFFFFF


class RV:
    def __init__(self, mem_size=8192):
        self.r = [0] * 32
        self.mem = bytearray(mem_size)
        self.r[2] = mem_size - 16  # sp near top
        self.pc = 0
        self.steps = 0

    def write(self, n, v):
        if n != 0:
            self.r[n] = u32(v)

    def signed(self, n):
        return s32(self.r[n])

    def lw(self, addr):
        addr = u32(addr)
        return int.from_bytes(self.mem[addr:addr + 4], 'little', signed=False)

    def sw(self, addr, v):
        addr = u32(addr)
        self.mem[addr:addr + 4] = u32(v).to_bytes(4, 'little')


def _parse_imm(s):
    s = s.strip()
    return int(s, 0)


def _parse_off_reg(s):
    m = re.match(r'(-?\w+)\s*\(\s*(\w+)\s*\)', s.strip())
    if not m:
        raise ValueError(f"bad offset(reg): {s!r}")
    return _parse_imm(m.group(1)), REGS[m.group(2)]


def assemble(source):
    """Return (instructions, labels). Strip comments and labels; ignore directives."""
    insns = []
    labels = {}
    pc = 0
    for raw in source.split('\n'):
        line = re.sub(r'[#;].*$', '', raw).strip()
        if not line:
            continue
        # Strip leading labels (possibly multiple on same line)
        while ':' in line:
            i = line.index(':')
            tok = line[:i].strip()
            if not tok or ' ' in tok or '(' in tok or ',' in tok:
                break
            labels[tok] = pc
            line = line[i + 1:].strip()
        if not line or line.startswith('.'):
            continue
        parts = re.split(r'\s+', line, maxsplit=1)
        op = parts[0].lower()
        args_str = parts[1] if len(parts) > 1 else ''
        args = [a.strip() for a in re.split(r',\s*', args_str) if a.strip()]
        insns.append((op, args))
        pc += 4
    return insns, labels


def run(source, *, entry='main', max_steps=10_000_000, mem_size=8192,
        regs=None, mem_init=None):
    cpu = RV(mem_size)
    if regs:
        for k, v in regs.items():
            cpu.write(REGS[k], v)
    if mem_init:
        for addr, val in mem_init:
            cpu.sw(addr, val)
    insns, labels = assemble(source)
    if entry not in labels:
        raise ValueError(f"entry label {entry!r} not found; labels={list(labels)}")
    cpu.pc = labels[entry]
    # Magic return-from-top: set ra to a sentinel beyond code
    sentinel = len(insns) * 4
    cpu.write(1, sentinel)

    while 0 <= cpu.pc < len(insns) * 4:
        cpu.steps += 1
        if cpu.steps > max_steps:
            raise RuntimeError(f"max_steps {max_steps} exceeded at pc={cpu.pc}")
        op, args = insns[cpu.pc // 4]
        nxt = cpu.pc + 4

        def R(i):
            if args[i] not in REGS:
                raise ValueError(f"unknown register {args[i]!r} at pc={cpu.pc}")
            return REGS[args[i]]

        try:
            if op in ('add', 'sub', 'and', 'or', 'xor', 'sll', 'srl', 'sra', 'slt', 'sltu',
                      'mul', 'mulh', 'mulhu', 'mulhsu', 'div', 'divu', 'rem', 'remu'):
                rd, rs1, rs2 = R(0), R(1), R(2)
                a, b = cpu.signed(rs1), cpu.signed(rs2)
                ua, ub = cpu.r[rs1], cpu.r[rs2]
                if op == 'add': cpu.write(rd, a + b)
                elif op == 'sub': cpu.write(rd, a - b)
                elif op == 'and': cpu.write(rd, ua & ub)
                elif op == 'or': cpu.write(rd, ua | ub)
                elif op == 'xor': cpu.write(rd, ua ^ ub)
                elif op == 'sll': cpu.write(rd, ua << (ub & 31))
                elif op == 'srl': cpu.write(rd, ua >> (ub & 31))
                elif op == 'sra': cpu.write(rd, a >> (ub & 31))
                elif op == 'slt': cpu.write(rd, 1 if a < b else 0)
                elif op == 'sltu': cpu.write(rd, 1 if ua < ub else 0)
                elif op == 'mul': cpu.write(rd, a * b)
                elif op == 'mulh': cpu.write(rd, (a * b) >> 32)
                elif op == 'mulhu': cpu.write(rd, (ua * ub) >> 32)
                elif op == 'mulhsu': cpu.write(rd, (a * ub) >> 32)
                elif op == 'div': cpu.write(rd, -1 if b == 0 else (a // b if (a < 0) == (b < 0) or a % b == 0 else a // b + 1))
                elif op == 'divu': cpu.write(rd, 0xFFFFFFFF if ub == 0 else ua // ub)
                elif op == 'rem': cpu.write(rd, a if b == 0 else a - b * (a // b if (a < 0) == (b < 0) or a % b == 0 else a // b + 1))
                elif op == 'remu': cpu.write(rd, ua if ub == 0 else ua % ub)
            elif op in ('addi', 'andi', 'ori', 'xori', 'slli', 'srli', 'srai', 'slti', 'sltiu'):
                rd, rs1, imm = R(0), R(1), _parse_imm(args[2])
                a, ua = cpu.signed(rs1), cpu.r[rs1]
                if op == 'addi': cpu.write(rd, a + imm)
                elif op == 'andi': cpu.write(rd, ua & u32(imm))
                elif op == 'ori': cpu.write(rd, ua | u32(imm))
                elif op == 'xori': cpu.write(rd, ua ^ u32(imm))
                elif op == 'slli': cpu.write(rd, ua << (imm & 31))
                elif op == 'srli': cpu.write(rd, ua >> (imm & 31))
                elif op == 'srai': cpu.write(rd, a >> (imm & 31))
                elif op == 'slti': cpu.write(rd, 1 if a < imm else 0)
                elif op == 'sltiu': cpu.write(rd, 1 if ua < u32(imm) else 0)
            elif op == 'lw':
                rd = R(0); off, base = _parse_off_reg(args[1])
                cpu.write(rd, cpu.lw(cpu.r[base] + off))
            elif op == 'sw':
                rs = R(0); off, base = _parse_off_reg(args[1])
                cpu.sw(cpu.r[base] + off, cpu.r[rs])
            elif op == 'li':
                cpu.write(R(0), _parse_imm(args[1]))
            elif op == 'mv':
                cpu.write(R(0), cpu.r[R(1)])
            elif op == 'neg':
                cpu.write(R(0), -cpu.signed(R(1)))
            elif op == 'not':
                cpu.write(R(0), ~cpu.r[R(1)])
            elif op == 'nop':
                pass
            elif op == 'j':
                nxt = labels[args[0]]
            elif op == 'jal':
                if len(args) == 1:
                    cpu.write(1, cpu.pc + 4)
                    nxt = labels[args[0]]
                else:
                    cpu.write(R(0), cpu.pc + 4)
                    nxt = labels[args[1]]
            elif op == 'jr':
                nxt = cpu.r[R(0)]
            elif op == 'jalr':
                if len(args) == 1:
                    cpu.write(1, cpu.pc + 4)
                    nxt = cpu.r[R(0)]
                else:
                    cpu.write(R(0), cpu.pc + 4)
                    nxt = cpu.r[R(1)]
            elif op == 'ret':
                nxt = cpu.r[1]
            elif op in ('beq', 'bne', 'blt', 'bge', 'bltu', 'bgeu'):
                a, b = cpu.signed(R(0)), cpu.signed(R(1))
                ua, ub = cpu.r[R(0)], cpu.r[R(1)]
                lab = args[2]
                cond = {
                    'beq': a == b, 'bne': a != b, 'blt': a < b, 'bge': a >= b,
                    'bltu': ua < ub, 'bgeu': ua >= ub,
                }[op]
                if cond: nxt = labels[lab]
            elif op in ('beqz', 'bnez', 'bgez', 'bltz'):
                a = cpu.signed(R(0))
                cond = {'beqz': a == 0, 'bnez': a != 0, 'bgez': a >= 0, 'bltz': a < 0}[op]
                if cond: nxt = labels[args[1]]
            elif op == 'ecall':
                return cpu
            else:
                raise NotImplementedError(f"unsupported instruction {op!r} at pc={cpu.pc}")
        except KeyError as e:
            raise RuntimeError(f"missing label/register at pc={cpu.pc}: {e}")

        if nxt >= len(insns) * 4:
            return cpu
        cpu.pc = nxt
    return cpu
PYEOF

