import importlib.util; spec = importlib.util.spec_from_file_location('rvi','/tmp/eval_rvbrev/rvi.py'); rvi = importlib.util.module_from_spec(spec); spec.loader.exec_module(rvi); src = open('/tmp/eval_rvbrev/code.s').read()
def pyrev(x):
    r = 0
    for _ in range(32):
        r = (r << 1) | (x & 1); x >>= 1
    return r
for x in [0, 1, 0xDEADBEEF, 0x80000001, 0x12345678]:
    cpu = rvi.run(src, entry='bitrev', regs={'a0': x})
    got = cpu.r[rvi.REGS['a0']]
    assert got == pyrev(x), f'bitrev({hex(x)}) got {hex(got)}'
print('OK')
